import galleryData from "../data/GaleriaFotos.jsx";

const MasonryGrid = () => {
  return (
    <div className="columns-1 sm:columns-2 md:columns-3 gap-4 space-y-4">
      {galleryData.map((img) => (
        <img
          key={img.id}
          src={img.src}
          alt={img.alt}
          className="w-full rounded-xl break-inside-avoid shadow-md hover:scale-[1.02] transition"
        />
      ))}
    </div>
  );
};

export default MasonryGrid;
